const __pageData = JSON.parse('{"title":"多模型的范畴构造与极限语义","description":"构造模型范畴 Models，分析极限、余极限、拉回、推出与笛卡尔闭性的程序语义解释，及其在跨框架工具链设计与版本合并中的工程映射","frontmatter":{"title":"多模型的范畴构造与极限语义","description":"构造模型范畴 Models，分析极限、余极限、拉回、推出与笛卡尔闭性的程序语义解释，及其在跨框架工具链设计与版本合并中的工程映射","date":"2026-05-01T00:00:00.000Z","tags":["理论前沿","形式化方法","范畴论","模型范畴","极限与余极限","笛卡尔闭性"],"category":"theoretical-foundations"},"headers":[],"relativePath":"theoretical-foundations/mm-05-multi-model-category.md","filePath":"theoretical-foundations/mm-05-multi-model-category.md","lastUpdated":1777741461000}');
